  private static Type getActualTypeFromHierarchy(TypeVariable<?> fieldTypeVariable, Type parentType, Class<?> rawParentClass) {
    // Walk up the class hierarchy to resolve the type variable
    // First, check if we can get generic superclass information
    Type genericSuperclass = rawParentClass.getGenericSuperclass();

    if (genericSuperclass instanceof ParameterizedType) {
      ParameterizedType paramSuperType = (ParameterizedType) genericSuperclass;
      Class<?> superClass = (Class<?>) paramSuperType.getRawType();

      // Check if the type variable is defined in this superclass
      TypeVariable<?>[] superClassTypeVars = superClass.getTypeParameters();
      int indexInSuper = getIndexSafe(superClassTypeVars, fieldTypeVariable);

      if (indexInSuper != -1) {
        // Found it! Return the corresponding actual type from the parameterized type
        Type[] superClassActualTypes = paramSuperType.getActualTypeArguments();
        return superClassActualTypes[indexInSuper];
      } else {
        // Recursively check further up the hierarchy
        return getActualType(paramSuperclass, paramSuperType, superClass);
      }
    }

    // Also check interfaces for the type variable
    Type[] genericInterfaces = rawParentClass.getGenericInterfaces();
    Class<?>[] interfaces = rawParentClass.getInterfaces();

    for (int i = 0; i < genericInterfaces.length; i++) {
      Type genericInterface = genericInterfaces[i];
      if (genericInterface instanceof ParameterizedType) {
        ParameterizedType paramIntfType = (ParameterizedType) genericInterface;
        Class<?> intfClass = interfaces[i];

        TypeVariable<?>[] intfTypeVars = intfClass.getTypeParameters();
        int indexInIntf = getIndexSafe(intfTypeVars, fieldTypeVariable);

        if (indexInIntf != -1) {
          Type[] intfActualTypes = paramIntfType.getActualTypeArguments();
          return intfActualTypes[indexInIntf];
        }
      }
    }

    // If it's not found anywhere in the hierarchy, we can't resolve it
    throw new IllegalStateException(
        "Could not resolve type variable '" + fieldTypeVariable.getName() + 
        "' in the class hierarchy of " + rawParentClass.getName());
  }
}

