private static Type getActualTypeFromHierarchy(TypeVariable<?> fieldTypeVariable, Type parentType, Class<?> rawParentClass) {
  // Walk up the class hierarchy to resolve the type variable
  return resolveTypeVariableFromHierarchy(fieldTypeVariable, rawParentClass);
}

private static Type resolveTypeVariableFromHierarchy(TypeVariable<?> fieldTypeVariable, Class<?> clazz) {
  // Get the declaring class of the type variable
  Class<?> declaringClass = (Class<?>) fieldTypeVariable.getGenericDeclaration();

  // Walk up the class hierarchy starting from the given class
  Class<?> currentClass = clazz;
  Type currentType = currentClass;

  while (currentClass != null && currentClass != Object.class) {
    // Check the generic superclass
    Type genericSuperclass = currentClass.getGenericSuperclass();
    if (genericSuperclass instanceof ParameterizedType) {
      ParameterizedType paramSuperType = (ParameterizedType) genericSuperclass;
      Class<?> superClass = (Class<?>) paramSuperType.getRawType();

      // If this superclass is where the type variable is declared
      if (superClass == declaringClass) {
        TypeVariable<?>[] superClassTypeVars = superClass.getTypeParameters();
        int indexInSuper = getIndexSafe(superClassTypeVars, fieldTypeVariable);

        if (indexInSuper != -1) {
          Type[] superClassActualTypes = paramSuperType.getActualTypeArguments();
          return superClassActualTypes[indexInSuper];
        }
      }

      // Continue up the hierarchy
      currentClass = superClass;
      currentType = paramSuperType;
    } else if (genericSuperclass instanceof Class<?>) {
      currentClass = (Class<?>) genericSuperclass;
    } else {
      currentClass = currentClass.getSuperclass();
    }

    // If we've reached the declaring class, we can stop
    if (currentClass == declaringClass) {
      break;
    }
  }

  // Also check interfaces recursively
  Type resolvedFromInterface = resolveTypeVariableFromInterfaces(fieldTypeVariable, clazz);
  if (resolvedFromInterface != null) {
    return resolvedFromInterface;
  }

  // If it's not found anywhere in the hierarchy, we can't resolve it
